SELECT n.*, ste.site_nm AS site_nm, prd.prod_nm AS prod_nm, mem.member_nm AS member_nm FROM pd_restock_noti n LEFT JOIN sy_site ste ON ste.site_id = n.site_id LEFT JOIN pd_prod prd ON prd.prod_id = n.prod_id LEFT JOIN mb_member mem ON mem.member_id = n.member_id
ORDER BY n.restock_noti_id ASC ORDER BY n.restock_noti_id DESC ORDER BY n.reg_date ASC ORDER BY n.reg_date DESC ORDER BY n.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

